var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"소장님! 이쪽을 좀 봐 주세요!","JPN":"少将！　こちらを向いてください！","ENG":"Major General, please look here!","TWN":"少將大人！請看這邊！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"정말로 이제 전쟁이 끝난 겁니까?","JPN":"本当に戦争は終わったのでしょうか？","ENG":"Is the war really over now?","TWN":"戰爭真的結束了嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_02"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"고향으로 돌아가지 못하고 있는 난민들에게 한 말씀 부탁드립니다!","JPN":"故郷に帰れずにいる難民たちに一言を！","ENG":"Can you say something to the refugees who have lost their homes?","TWN":"請對沒辦法回家鄉的難民們說句話吧！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_CAMERA"},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"소장님! 저희 측에서 입수한 제보에 따르면 지난 달에 있었던 국가재난 경보는 오류가 아니었다고 하던데 사실입니까?","JPN":"少将！　入手した情報によると、\\n先月の国家災害警報は誤りではないそうですが、事実でしょうか？","ENG":"Major General, our source says the national disaster alert didn't go off in error last month. Is that true?","TWN":"少將大人！有人舉報說，上個月發佈的國家災難警報並非誤報，請問這是真的嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"그 당시, 관리국 방위권 내에서 측정가능한 계수를 뛰어넘는 고밀도 침식파가 관측되었다고 들었습니다!","JPN":"当時、管理局の防衛圏域内で測定上限を越える\\n高密度侵食波が観測されたという情報が！","ENG":"Is it also true that an immeasurably high-density Corruption Ray was detected within the defensive range of the Administration?","TWN":"聽說當時在管理局防衛圈內，觀測到超出可測係數的高密度侵蝕波！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_02"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"정말 국민들에게 진실을 말하고 있는 게 맞나요?!","JPN":"国民に対して、本当のことを話しているのですか！？","ENG":"Are you really telling the truth to the people?","TWN":"您對國民發表的言論是真實的嗎？！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_02"},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"고위침식체의 잔존 가능성에 대해 대외적으로 은폐를 하고 있는 건 아닙니까?!","JPN":"高位侵食体の残存の可能性について、対外的に隠ぺい工作をしているのでは！？","ENG":"Are you not publicly lying about the possibility of remaining high-ranking C.O.s?","TWN":"您是不是在對外隱瞞高級侵蝕體殘存的可能性？！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_CAMERA"},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......신경 쓰실 것 없습니다. 저쪽은 제가 상대하죠.","JPN":"……お気になさらず。あちらは私が対処いたします。","ENG":"Don't worry. I'll take care of them.","TWN":"……沒什麼需要您費心的事情。那裡就交給我來應付吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만......","JPN":"だが……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"괜찮습니다. 가시죠, 사령관님.","JPN":"心配無用です。どうぞこちらへ、司令官。","ENG":"Don't. Commander, let's go.","TWN":"沒關係。走吧，司令官。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그 아이는......","JPN":"あの子のことは……","ENG":"She...","TWN":"那孩子……"},"stage":{"bg":"black","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"사령관님......","JPN":"司令官……","ENG":"Commander.","TWN":"司令官……"},"stage":{"bg":"black","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_KNOCK_WOOD"},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"사령관님!","JPN":"司令官！","ENG":"Commander!","TWN":"司令官！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_KNOCK_WOOD"},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"응?! 아아......","JPN":"うむ！？　ああ……","ENG":"Huh? Ah...","TWN":"嗯？！啊啊……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"미안해, 잠시 졸았나 보군. 언제 들어왔나?","JPN":"すまない、ちょっと居眠りをしてしまったみたいだ。\\nいつからそこに？","ENG":"I'm sorry, I must have fallen asleep. When did you come?","TWN":"抱歉，看來我打了瞌睡。你什麼時候進來的？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"방금 전입니다.","JPN":"ついさきほどからです。","ENG":"Just now.","TWN":"就在剛才。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"잠든 모습은 오랜만에 보는군요. 피곤하셨나 보죠?","JPN":"そんな姿を見たのは久々です。お疲れのようですね。","ENG":"I haven't seen you sleeping for a long time. You must have been really tired.","TWN":"許久不見您睡著的樣子了。您似乎很疲憊的樣子？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그러게 말이야. 괜찮다고 생각했는데 역시 나이는 못 속이는 모양이지.","JPN":"そうだな、まだまだだと思ったが、やはり寄る年波には勝てないようだ。","ENG":"I must have. I thought I was fine, but I can't defy my age after all.","TWN":"就是啊。原本還覺得自己沒問題，但果然，歲月不饒人啊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"못 속이는 건 그것만이 아니죠.","JPN":"勝てないものは他にもあるのでは？","ENG":"That's not the only thing you can't defy.","TWN":"歲月不饒人的地方可不止這些。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"잠꼬대를 꽤 하시던데...... 요즘도 악몽을 꾸십니까?","JPN":"寝言を言っていましたが……今でも悪夢を見るのですか？","ENG":"You were talking in your sleep. Do you still have nightmares?","TWN":"您說了不少夢話……最近仍在做噩夢嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"설마 제이나의 일 때문에 아직도 신경 쓰시는 거라면 그건 소장님의 책임이 아닙니다.","JPN":"ジェイナの件でしたら、あれは少将の責任ではありません。","ENG":"If you're still thinking about what happened to Jaina, don't. It wasn't your fault.","TWN":"您該不會還在在意婕娜的事情吧？那件事並不是少將的責任。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......보직 변경하려면 아직 며칠 더 남은 것 같은데 벌써부터 정보부 사람이 다 된 것 같군.","JPN":"……まだ人事異動前だというのに、すっかり情報局の人間のような口ぶりだな。","ENG":"You still have a few days left before your transfer, and you're already acting like a member of the Intelligence Agency.","TWN":"……離你換崗還有幾天吧，怎麼就已經像個情報部的人了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이젠 그쪽에서 내 꿈자리까지 보고하라고 하나 보지?","JPN":"向こうから私の夢のことまで報告しろと言われているのか？","ENG":"Why, do your superiors even want to know what I dream about?","TWN":"難道情報部要你把我做的夢也上報嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......소장님은 요주의 인물이니까요.","JPN":"……少将は要注意人物ですからね。","ENG":"You're a person of interest, Major General.","TWN":"……因為少將大人是特別需要被注意的人物。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하하, 알래스카 촌구석에서 온 러시아 이민자 3세 꼬마가 별 두 개를 달았으니 눈에 거슬려 하는 사람도 당연히 있겠지.","JPN":"ハハハ、アラスカの田舎出身のロシア移民3世が\\n二つも星をつけてるのだから、目の敵にする奴も当然いるだろう。","ENG":"Hah hah. Sure. A third-generation Russian immigrant from the backwater Alaska has become a two-star general. Of course, some people aren't happy about that.","TWN":"哈哈，從阿拉斯加鄉下來的俄羅斯三代移民小鬼戴了兩顆星，當然會有看不順眼的人了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네라면 업무관계상 그런 친구들을 자주 만날 것 같은데, 조금만 더 참으라고 전해 주게.","JPN":"君は業務上そういった連中に会うことも多いだろうから、\\nあと少しの辛抱だと伝えておいてくれたまえ。","ENG":"You meet people like them often for business, don't you? Please tell them that they won't have to put up with me for too long.","TWN":"你大概會因為業務的關係，經常見到這些朋友，那就幫我轉告他們，要他們再忍耐一下吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"어차피 다음달이면 난 예편이니까.","JPN":"どのみち、来月になれば私は引退だ。","ENG":"I'll be discharged next month.","TWN":"反正下個月我就退役了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"정말 은퇴하실 겁니까?","JPN":"本当に引退するおつもりですか？","ENG":"Are you really going to retire?","TWN":"您真的要隱退嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"벌써 오래 전에 결정된 일이야. 왜 그런 걸 묻고 그래?","JPN":"とっくに決まったことだ、なぜそんなことを聞く？","ENG":"This was decided a long time ago. Why do you ask?","TWN":"我很久之前就已經決定好了。為什麼要問這個？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"결정은 언제든지 번복될 수 있습니다. 의지만 있다면 말이죠.","JPN":"決定はいつでも覆すことができます。\\nその意思さえあれば、ですが。","ENG":"You can change your decision anytime. If you want, that is.","TWN":"決定是隨時可以推翻的。只要有這個想法的話。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"미안하지만 난 그럴 의지가 없어.","JPN":"悪いが、私にそのつもりはない。","ENG":"Sorry, but I don't want to change it.","TWN":"抱歉，我沒有這種想法。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"소장님은 영웅입니다.","JPN":"少将は英雄です。","ENG":"Major General, you're a hero.","TWN":"少將大人是英雄。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그리고 영웅은 영웅의 의무를 다해야 합니다.","JPN":"そして、英雄たるものは英雄としての責任を全うすべきです。","ENG":"And as a hero, you have duties to fulfill.","TWN":"英雄就應該盡英雄的義務。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......자네까지 그런 말을 할 줄은 몰랐군.","JPN":"……君までそんなことを言うとはな。","ENG":"Never thought I'd hear you say that.","TWN":"……我沒想到連你都會說這種話。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"요즘 안경 도수가 잘 안 맞는 것 같은데 다시 한 번 날 자세히 보라고.","JPN":"どうやら眼鏡の度数が合ってないようだな。\\n目を凝らしてもう一度私を見てみるが良い。","ENG":"Maybe you need new glasses. Take a look at me again.","TWN":"看來你最近眼鏡度數不太對啊，再仔細看看我吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"난 이제 전장보다 흔들의자와 베이글이 더 잘 어울리는 할머니야.","JPN":"私はもう、戦場よりも揺り椅子やベーグルのほうが似合う年寄りだよ。","ENG":"I'm an old woman who looks more at home sitting on a rocking chair eating bagels than fighting on the battlefield.","TWN":"比起戰場，我這個老奶奶更適合搖椅和貝果。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 영웅 같은 건 더 이상 필요 없어.","JPN":"それに、英雄なんてものはこれ以上必要ない。","ENG":"And mankind doesn't need heroes anymore.","TWN":"而且人類已經不再需要英雄了，"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"인류에게 필요한 건 잘 짜여진 조직과 적절한 매뉴얼이지.","JPN":"人類に必要なものは、良い組織と適切なマニュアルだ。","ENG":"What it really needs is a well-organized group with a well-thought-out manual.","TWN":"他們需要的是嚴密的組織和適當的指令。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"내가 그걸 위해 오랫동안 노력해 왔다는 걸 잘 알 텐데?","JPN":"私がそのために長い間努力してきたことをよく知っているはずだが？","ENG":"And you of all people should know how hard I've worked for that.","TWN":"你應該知道我為了這個，奮鬥了很長一段時間吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......그 햇병아리들 말입니까?","JPN":"……あのひよっこたちのことですか？","ENG":"Are you talking about those fledglings?","TWN":"……您是指那些小雛鳥嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>다음 세대를 책임질</color> 햇병아리들이지.","JPN":"<color=#ffd34c>次世代を担う</color>ひよっこたちだ。","ENG":"The fledglings that will <color=#ffd34c>take care of our future generations</color>.","TWN":"是<color=#ffd34c>背負著下個時代</color>的小雛鳥們。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그 햇병아리들이 제 몫을 하게 되고...... 또 다른 햇병아리를 키우고......","JPN":"あのひよっこたちが一人前になって……また別のひよっこを育てる……","ENG":"Once they grow enough to do their bit, they can train other fledglings.","TWN":"讓這些小雛鳥能夠獨當一面……然後再去培養新的小雛鳥……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그러다 보면 더 이상 영웅이 필요 없는 시대가 올 거야.","JPN":"そうしているうちに、英雄が不要になる時代が来るだろう。","ENG":"If that keeps up, eventually the world won't need heroes anymore.","TWN":"這麼一來，不再需要英雄的時代就會到來了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"관리 실패 같은 일이 다시 벌어지더라도 충분히 대응할 수 있겠지.","JPN":"管理失敗のようなことが再発しても、十分対応できるようになるだろうな。","ENG":"And it'll be strong enough to handle another Administration Failure, if it happens.","TWN":"就算再度發生像管理失敗這樣的事情，他們應該也足以應對了吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"하지만......","JPN":"しかし……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"뭐, 그때까지는 자네가 있으니까.","JPN":"まあ、それまでは君がいることだしな。","ENG":"Well, until then, it's got you.","TWN":"而且，那時候你也會在那裡的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아, 그러고 보니 인사가 늦었군. 소장 진급 축하하네.","JPN":"ああ、そういえばお祝いができてなかったな。少将進級おめでとう。","ENG":"Ah, I almost forgot. Congratulations on your promotion to Major General.","TWN":"啊，話說回來，我還沒祝賀你呢。恭喜你晉升為少將。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"계급장은 다음 달 후에나 받게 되겠지만.","JPN":"階級章は来月以降に受け取ると思うが","ENG":"Even though you won't get your badge for a couple of months.","TWN":"雖然軍銜徽章下個月才會拿到。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그때쯤이면 난 민간인일 테니까 냄새 나는 장교클럽 말고 다운타운의 클럽하우스에서 보자고.","JPN":"その頃私は民間人になっているだろうから、\\nショボい将校クラブではなく街のクラブハウスで会おう。","ENG":"By then, I'll be a civilian. You can see me at the clubhouse downtown instead of that smelly officers' club.","TWN":"那時我應該就是個普通民眾了，所以我們就不要再到這種臭烘烘的軍官俱樂部了，去市中心的俱樂部見面吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"내가 한 잔 사지.","JPN":"私が一杯奢ってやろう。","ENG":"I'll buy you a drink.","TWN":"我請你喝一杯。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......알겠습니다.","JPN":"……わかりました。","ENG":"I'd love that.","TWN":"……知道了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"하지만 소장님......","JPN":"ですが、少将……","ENG":"But Major General,","TWN":"但是少將大人……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"대응할 수 없는 위기에 대응해야만 하기에...... 우리는 영웅이 필요한 겁니다.","JPN":"対応困難な危機に直面しているので……我々には英雄が必要なのです。","ENG":"we need heroes, because there are still crises that only heroes can deal with.","TWN":"當我們不得不面對無法應對的危機時……我們還是需要英雄的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};